@code {
    private AppointmentModel Model { get; set; } = new();

    private bool showStep2;
    private bool availabilityChecked;
    private bool bookingConfirmed;

    private List<string> doctors = [];
    private List<string> availableSlots = [];
    private Dictionary<string, string> serverErrors = new();

    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        doctors = await AppointmentSvc.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Validate step 1 fields manually
        editContext = new EditContext(Model);
        editContext.EnableDataAnnotationsValidation();

        if (editContext.Validate())
        {
            // Only proceed if the four step-1 fields are valid
            var step1Valid =
                !string.IsNullOrWhiteSpace(Model.PatientName) &&
                !string.IsNullOrWhiteSpace(Model.Email) &&
                !string.IsNullOrWhiteSpace(Model.Phone) &&
                !string.IsNullOrWhiteSpace(Model.InsuranceProvider);

            if (step1Valid)
            {
                showStep2 = true;
            }
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        availabilityChecked = false;
        serverErrors.Clear();
    }

    private async Task OnDoctorOrDateChanged()
    {
        availabilityChecked = false;
        serverErrors.Clear();
        availableSlots = [];
        Model.TimeSlot = string.Empty;

        if (!string.IsNullOrEmpty(Model.Doctor) && Model.Date != default)
        {
            availableSlots = await AppointmentSvc.GetAvailableSlotsAsync(
                Model.Doctor, DateOnly.FromDateTime(Model.Date));
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();

        // Client-side validation first
        editContext = new EditContext(Model);
        editContext.EnableDataAnnotationsValidation();

        if (!editContext.Validate())
        {
            return;
        }

        // Server-side business-rule validation
        var errors = await AppointmentSvc.ValidatePatientAsync(
            Model.Email,
            Model.InsuranceProvider,
            Model.Doctor,
            Model.TimeSlot);

        if (errors.Count > 0)
        {
            serverErrors = errors;
            availabilityChecked = false;
            return;
        }

        availabilityChecked = true;
    }

    private void HandleSubmit()
    {
        if (!availabilityChecked) return;
        bookingConfirmed = true;
    }
}
"}

